spec:
// Electron Build Scripts in package.json
interface ElectronScripts {
  "electron:compile": "tsc -p electron/tsconfig.json",
  "electron:dev": "concurrently -k \"npm run web\" \"npm run electron:compile && electron electron/main.js\"",
  "electron:build": "npm run build:web && npm run electron:compile",
  "electron:package": "npm run electron:build && electron-builder --config electron/electron-builder.yml",
  "electron:package:mac": "npm run electron:build && electron-builder --config electron/electron-builder.yml --mac",
  "electron:package:win": "npm run electron:build && electron-builder --config electron/electron-builder.yml --win",
  "electron:package:linux": "npm run electron:build && electron-builder --config electron/electron-builder.yml --linux"
}

// Required devDependencies (escalated - need to install):
// electron, electron-builder, concurrently, @electron/notarize

// Build outputs:
// - Development: Runs Expo web server + Electron window
// - Package: Creates distributables in electron-dist/
//   - macOS: DMG, ZIP (x64, arm64)
//   - Windows: NSIS installer, Portable (x64)
//   - Linux: AppImage, DEB (x64, arm64)

// Documentation: docs/ELECTRON_BUILD.md
